前端大文件批量文件上传方案 上传的是ppvod切片服务器
支持：秒传、断点续传、分片上传

## vue2 大文件上传 秒传、断点续传、分片上传


### 大文件上传流程图
![](/images/bigfile-slice-upload.png)

### 组件页面
``` bash
//大文件上传组件
Vue.component('UploadFile', {
    template:`
        <div>
            <div style="width:100%">
                <el-upload action="#" 
                    :show-file-list="false" 
                    :on-change="handleFileSelect" 
                multiple>
                    <el-button  type="primary">点击上传</el-button>
                </el-upload>
                <div v-if="isShowProgress" v-for="(file, index) in files" class="el-upload-progress">
                        <!-- 进度条上方文件名 -->
                        <div class="upload-filename">
                        <div>{{ file.name }} - {{ file.status }}<i class="el-icon-circle-close" @click="deleteFile(index)"></i></div>
                        </div>
                        <!-- 进度条 -->
                        <el-progress
                        style="width: 450px"
                        :percentage="progressPercent" 
                        :text-inside="true"
                        :color="customColor"
                        :stroke-width="4"
                        >
                        </el-progress>
                        <!-- 进度条数字 -->
                        <el-input  v-model="file.url" autoComplete="off" clearable  placeholder="请输入地址"></el-input>
                        <el-input  v-model="file.playtime" autoComplete="off" clearable  placeholder="视频时长"></el-input>
                </div>
    		</div>
        </div>
    `,
```

### 批量上传文件  需要对每个切片进行文件校验 整体文件也是
``` bash
/**
* 添加文件 -- 多文件上传
* @param {*} files 文件列表
*/
async add(files) {
    this.log('有文件进来了')
    // 绑定一个文件添加完成事件
    this.out('OnFileAddStart', files);
    for (let i=0; i < files.length; i++ ){

    const file = files[i];
    const ext = '.' +file.type.split('/')[1];
    // 验证文件类型
    if (this.mimeTypes.indexOf(ext) === -1) {
        this.log('文件类型不支持')
        return
    };

    //   const fileMd5 = await this.getFileMd5(file);
    let fileMd5 = "";
    await this.getFileMd5(file)
        .then(md5 => {
            fileMd5 = md5;
            this.log("计算MD5值:", fileMd5);
        })
        .catch(err => {
            this.log("计算MD5失败:", err);
        });



    // 验证文件是否已经再上传列表中
    if (this.files.findIndex(item => item.md5 === fileMd5) !== -1) {
        this.log('文件已经在上传列表中')
        // 跳过 循环
        continue
    }

    // 获取视频时长
    let playTime = "";
        await this.getVideoTime(file)
        .then(duration => {
            playTime = duration;
            this.log("视频时长:", duration, "秒");
        })
        .catch(err => {
            this.log("获取视频时长失败:", err);
        });

    // 获取文件封面
    // const fileCover = await this.getFileCover(file,i);
    // const fileCover = '';
    var fileblock = {
        fileChunks: this.slicer(file),
        blockNum: Math.ceil(file.size / this.chunkSize), // 分片数量
        upchunk: 0, // 已上传分片数量
        uploaded: 0, // 已上传 字节
    //   cover: fileCover,
        status: '准备',// 上传状态
        chunkprogress: {byte: 0,percent:0}, // 分片上传进度
        name: file.name,
        size: file.size,
        type: file.type,
        lastModifiedDate: file.lastModifiedDate,
        md5: fileMd5,
        uniqueFileName: md5('' + this.uploadkey + file.name + file.type + file.lastModifiedDate + file.size),
        cancel: null,
        url: '',
        playtime: playTime,
    }
    this.log("切片文件", fileblock);
    this.files.push(fileblock) 
    this.log('第' + i + '个文件切片成功')
    this.out('OnFileChunk', { file:fileblock, index: i })
    this.oneUpload(i, fileblock)
    }
    this.log('所有文件切片成功')
    this.out('OnFileAddEnd', this.files)

},
```

